export interface CSVParseOptions {
  delimiter?: string;
  quoteChar?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult<T extends Record<string, any> = Record<string, any>> {
  rows: T[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: T, index: number) => boolean): T[];
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<any, T[]>;
}

class CSVResultImpl<T extends Record<string, any>> implements CSVResult<T> {
  rows: T[];
  headers: string[];
  errors: CSVError[];

  constructor(rows: T[], headers: string[], errors: CSVError[]) {
    this.rows = rows;
    this.headers = headers;
    this.errors = errors;
  }

  filter(predicate: (row: T, index: number) => boolean): T[] {
    return this.rows.filter(predicate);
  }

  sum(column: string): number {
    let total = 0;
    for (const row of this.rows) {
      const value = (row as any)[column];
      if (typeof value === "number" && !Number.isNaN(value)) {
        total += value;
      }
    }
    return total;
  }

  average(column: string): number {
    let total = 0;
    let count = 0;
    for (const row of this.rows) {
      const value = (row as any)[column];
      if (typeof value === "number" && !Number.isNaN(value)) {
        total += value;
        count += 1;
      }
    }
    return count === 0 ? 0 : total / count;
  }

  count(): number {
    return this.rows.length;
  }

  groupBy(column: string): Map<any, T[]> {
    const map = new Map<any, T[]>();
    for (const row of this.rows) {
      const key = (row as any)[column];
      if (!map.has(key)) {
        map.set(key, []);
      }
      map.get(key)!.push(row);
    }
    return map;
  }
}

export function parseCSV(input: string, options: CSVParseOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? ",";
  const quoteChar = options.quoteChar ?? '"';
  const lineSeparator = options.lineSeparator ?? "\n";

  const errors: CSVError[] = [];

  if (!input || input.length === 0) {
    return new CSVResultImpl([], [], errors);
  }

  const rows: string[][] = [];
  let currentField = "";
  let currentRow: string[] = [];
  let inQuotes = false;
  let i = 0;
  const len = input.length;

  const flushField = () => {
    currentRow.push(currentField);
    currentField = "";
  };

  const flushRow = () => {
    rows.push(currentRow);
    currentRow = [];
  };

  while (i < len) {
    const char = input[i];

    if (!inQuotes && input.startsWith(lineSeparator, i)) {
      flushField();
      flushRow();
      i += lineSeparator.length;
      continue;
    }

    if (!inQuotes && input.startsWith(delimiter, i)) {
      flushField();
      i += delimiter.length;
      continue;
    }

    if (char === quoteChar) {
      if (inQuotes) {
        const nextChar = input[i + 1];
        if (nextChar === quoteChar) {
          currentField += quoteChar;
          i += 2;
          continue;
        }
        inQuotes = false;
        i += 1;
        continue;
      }
      inQuotes = true;
      i += 1;
      continue;
    }

    currentField += char;
    i += 1;
  }

  if (inQuotes) {
    errors.push({ row: rows.length + 1, message: "Unterminated quoted field" });
  }

  flushField();
  flushRow();

  const headers = rows[0] ? rows[0].map((header) => header) : [];
  const dataRows = rows.slice(1);

  const parsedRows: Record<string, any>[] = [];

  const coerceValue = (value: string): any => {
    const trimmed = value.trim();
    if (trimmed.length === 0) {
      return null;
    }
    if (/^null$/i.test(trimmed)) {
      return null;
    }
    if (/^(true|false)$/i.test(trimmed)) {
      return /^true$/i.test(trimmed);
    }
    if (/^-?\d+(?:\.\d+)?$/.test(trimmed)) {
      return Number(trimmed);
    }
    return value;
  };

  dataRows.forEach((row, index) => {
    const rowNumber = index + 2;
    if (row.length !== headers.length) {
      errors.push({
        row: rowNumber,
        message: `Row has ${row.length} fields but expected ${headers.length}`,
      });
    }
    const record: Record<string, any> = {};
    headers.forEach((header, headerIndex) => {
      const value = row[headerIndex] ?? "";
      record[header] = coerceValue(value);
    });
    parsedRows.push(record);
  });

  return new CSVResultImpl(parsedRows, headers, errors);
}

import { parseCSV } from "./csv-parser";

const assert = (condition: any, message: string) => {
  if (!condition) {
    throw new Error(message);
  }
};

const assertEqual = (actual: any, expected: any, message: string) => {
  if (actual !== expected) {
    throw new Error(`${message}. Expected ${expected} but got ${actual}`);
  }
};

const testBasicParsing = () => {
  const input = "name,age\nAlice,30\nBob,25";
  const result = parseCSV(input);
  assertEqual(result.headers.length, 2, "headers length");
  assertEqual(result.rows.length, 2, "rows length");
  assertEqual(result.rows[0].name, "Alice", "first name");
  assertEqual(result.rows[0].age, 30, "age coercion");
};

const testQuotedFieldsWithCommas = () => {
  const input = "name,notes\nAlice,\"likes, commas\"";
  const result = parseCSV(input);
  assertEqual(result.rows[0].notes, "likes, commas", "quoted field with comma");
};

const testEscapedQuotes = () => {
  const input = "name,quote\nAlice,\"She said \"\"hi\"\"\"";
  const result = parseCSV(input);
  assertEqual(result.rows[0].quote, "She said \"hi\"", "escaped quotes");
};

const testCustomDelimiters = () => {
  const input = "name|age;\nAlice|30;\nBob|40;";
  const result = parseCSV(input, { delimiter: "|", lineSeparator: ";\n" });
  assertEqual(result.rows.length, 2, "custom delimiter rows");
  assertEqual(result.rows[1].age, 40, "custom delimiter age");
};

const testTypeCoercion = () => {
  const input = "a,b,c,d,e,f\n1,2.5,true,FALSE,null,";
  const result = parseCSV(input);
  const row = result.rows[0];
  assertEqual(row.a, 1, "int coercion");
  assertEqual(row.b, 2.5, "float coercion");
  assertEqual(row.c, true, "boolean true");
  assertEqual(row.d, false, "boolean false");
  assertEqual(row.e, null, "null coercion");
  assertEqual(row.f, null, "empty to null");
};

const testMalformedRowErrorCollection = () => {
  const input = "a,b\n1,2,3\n4";
  const result = parseCSV(input);
  assertEqual(result.errors.length, 2, "malformed row errors count");
  assertEqual(result.errors[0].row, 2, "first error row number");
};

const testFilterFunctionality = () => {
  const input = "name,age\nAlice,30\nBob,20\nCara,40";
  const result = parseCSV(input);
  const filtered = result.filter((row) => row.age > 25);
  assertEqual(filtered.length, 2, "filter count");
  assertEqual(filtered[0].name, "Alice", "filter first");
};

const testAggregationMethods = () => {
  const input = "name,score,group\nAlice,10,A\nBob,20,B\nCara,30,A";
  const result = parseCSV(input);
  assertEqual(result.sum("score"), 60, "sum");
  assertEqual(result.average("score"), 20, "average");
  assertEqual(result.count(), 3, "count");
  const grouped = result.groupBy("group");
  assertEqual(grouped.get("A")!.length, 2, "groupBy A count");
  assertEqual(grouped.get("B")!.length, 1, "groupBy B count");
};

const testEdgeCases = () => {
  const empty = parseCSV("");
  assertEqual(empty.rows.length, 0, "empty rows");
  assertEqual(empty.headers.length, 0, "empty headers");

  const singleColumn = parseCSV("value\n1\n2");
  assertEqual(singleColumn.rows[1].value, 2, "single column value");

  const singleRow = parseCSV("a,b,c\n1,2,3");
  assertEqual(singleRow.rows.length, 1, "single row count");

  const largeField = "x".repeat(10000);
  const large = parseCSV(`col\n\"${largeField}\"`);
  assertEqual(large.rows[0].col, largeField, "large field");
};

const runTests = () => {
  testBasicParsing();
  testQuotedFieldsWithCommas();
  testEscapedQuotes();
  testCustomDelimiters();
  testTypeCoercion();
  testMalformedRowErrorCollection();
  testFilterFunctionality();
  testAggregationMethods();
  testEdgeCases();
};

runTests();

