  while (i < len) {
    const char = input[i];

    if (!inQuotes && input.startsWith(lineSeparator, i)) {
      flushField();
      flushRow();
      i += lineSeparator.length;
      continue;
    }

    if (!inQuotes && input.startsWith(delimiter, i)) {
      flushField();
      i += delimiter.length;
      continue;
    }

    if (char === quoteChar) {
      if (inQuotes) {
        const nextChar = input[i + 1];
        if (nextChar === quoteChar) {
          currentField += quoteChar;
          i += 2;
          continue;
        }
        inQuotes = false;
        i += 1;
        continue;
      }
      inQuotes = true;
      i += 1;
      continue;
    }

    currentField += char;
    i += 1;
  }

  if (inQuotes) {
    errors.push({ row: rows.length + 1, message: "Unterminated quoted field" });
  }

  if (currentRow.length > 0 || currentField.length > 0) {
    flushField();
    flushRow();
  }

  const headers = rows[0] ? rows[0].map((header) => header) : [];
  const dataRows = rows.slice(1);

  const parsedRows: Record<string, any>[] = [];

  const coerceValue = (value: string): any => {
    const trimmed = value.trim();
    if (trimmed.length === 0) {
      return null;
    }
    if (/^null$/i.test(trimmed)) {
      return null;
    }
    if (/^(true|false)$/i.test(trimmed)) {
      return /^true$/i.test(trimmed);
    }
    if (/^-?\d+(?:\.\d+)?$/.test(trimmed)) {
      return Number(trimmed);
    }
    return value;
  };

  dataRows.forEach((row, index) => {
    const rowNumber = index + 2;
    if (row.length !== headers.length) {
      errors.push({
        row: rowNumber,
        message: `Row has ${row.length} fields but expected ${headers.length}`,
      });
    }
    const record: Record<string, any> = {};
    headers.forEach((header, headerIndex) => {
      const value = row[headerIndex] ?? "";
      record[header] = coerceValue(value);
    });
    parsedRows.push(record);
  });

  return new CSVResultImpl(parsedRows, headers, errors);
}
